export function getCategoryBySlug(slug: string): ToolCategory | undefined {
  return categories.find((c) => c.slug === slug);
}

export function getToolBySlug(slug: string): Tool | undefined {
  return tools.find((t) => t.slug === slug);
}

export function getToolsByCategory(categorySlug: string): Tool[] {
  return tools.filter((t) => t.categorySlug === categorySlug);
}

export function getRelatedTools(slugs: string[]): Tool[] {
  return slugs.map((slug) => getToolBySlug(slug)).filter((t): t is Tool => t !== undefined);
}
